pwsh -NoProfile -Command '
. ./New-EnvironmentMatrix.ps1
@{
  axes = [ordered]@{ os=@("ubuntu-latest","windows-latest"); node=@("18","20") }
} | ConvertTo-Json -Depth 10 | Set-Content /tmp/c1.json
Invoke-MatrixGenerator -ConfigPath /tmp/c1.json
Write-Host "---"
@{
  axes = [ordered]@{ os=@("ubuntu-latest","windows-latest"); node=@("18","20") }
  exclude = @( @{ os="windows-latest"; node="18" } )
  include = @( [ordered]@{ os="macos-latest"; node="20"; experimental=$true } )
  "fail-fast" = $false
  "max-parallel" = 2
} | ConvertTo-Json -Depth 10 | Set-Content /tmp/c2.json
Invoke-MatrixGenerator -ConfigPath /tmp/c2.json
Write-Host "---"
@{
  axes = [ordered]@{ os=@("ubuntu-latest"); feature=@("on","off") }
  "fail-fast" = $true
} | ConvertTo-Json -Depth 10 | Set-Content /tmp/c3.json
Invoke-MatrixGenerator -ConfigPath /tmp/c3.json
'

